// n8n webhook node configuration
const vexSDK = require('@vex_dev/sdk');

const policyId = 'ent-saas-n8n-ai-agent'; // Your Vex policy ID
const tenantId = $('Tenant ID').first().json.tenantId;

const payload = {
  action: 'ai_agent_execution',
  workflowId: $workflow.name,
  nodeName: $node.name,
  aiOutput: $('AI Agent').first().json.output,
  toolCalls: $('AI Agent').first().json.tool_calls || [],
  tenantId: tenantId,
  dataResidency: $('Customer Config').first().json.residency || 'US'
};

const client = new vexSDK.Client({
  apiKey: process.env.VEX_API_KEY
});

const result = await client.verify({
  policyId,
  payload,
  context: {
    executionId: $execution.id,
    timestamp: new Date().toISOString()
  }
});

if (!result.pass) {
  throw new Error(`Vex blocked: ${result.reason}`);
}

return [{ json: { vexPassed: true, result } }];

// Tool call validation webhook node
import { patternMatch } from '@vex_dev/sdk/patterns';

const toolCalls = $('AI Agent').first().json.tool_calls || [];
const suspiciousPatterns = [
  /sk-\w{48}/, // OpenAI keys
  /ak[A-Z0-9]{20}/, // AWS keys
  /(?i)(password|secret|key|token)[:=]\s*[\w\-]+/ // Generic creds
];

const violations = toolCalls.flatMap(call => 
  suspiciousPatterns
    .map(pattern => patternMatch(call.parameters, pattern))
    .filter(match => match)
);

if (violations.length > 0) {
  await fetch('https://api.vex.dev/v1/incident', {
    method: 'POST',
    headers: { 'Authorization': `Bearer ${process.env.VEX_API_KEY}` },
    body: JSON.stringify({
      policyId: 'n8n-credential-exposure',
      severity: 'critical',
      evidence: violations,
      workflowId: $workflow.id
    })
  });
  throw new Error('Credential exposure detected in tool parameters');
}

return [{ json: { toolCallsValidated: true } }];

// Tenant isolation validation node
const currentTenant = $('Auth').first().json.tenantId;
const targetTenant = $('AI Agent').first().json.target_tenant;
const residency = $('Customer Config').first().json.residency;

const allowedRegions = {
  'tenant-us-1': ['us-east-1', 'us-west-2'],
  'tenant-eu-1': ['eu-west-1', 'eu-central-1'],
  'tenant-ca-1': ['ca-central-1']
};

// Cross-tenant data flow check
if (currentTenant !== targetTenant) {
  throw new Error(`Cross-tenant violation: ${currentTenant} -> ${targetTenant}`);
}

// Data residency validation
const client = new (require('@vex_dev/sdk')).Client({ apiKey: process.env.VEX_API_KEY });
const residencyCheck = await client.verify({
  policyId: 'enterprise-data-residency',
  payload: {
    tenantId: currentTenant,
    actionResidency: $('Action Node').first().json.aws_region,
    contractResidency: residency,
    dataClassification: 'customer-pii'
  }
});

if (!residencyCheck.pass) {
  throw new Error(`Data residency violation: ${residencyCheck.reason}`);
}

return [{ json: { tenantIsolated: true, residencyCompliant: true } }];
